// Normalise le payload et construit sujet + HTML recap.
const p = $json.body ?? $json;
const eur = (n) => new Intl.NumberFormat('fr-FR',{style:'currency',currency:'EUR'}).format(Number(n)||0);
const c = p.contact || {};
let sujet = 'Nouvelle demande site';
let html = '';
if (p.type === 'contact') {
  sujet = `Contact site — ${c.nom||''}`;
  html = `<h2>Demande de contact</h2><ul><li><b>Nom :</b> ${c.nom||''}</li><li><b>Coordonnées :</b> ${c.coordonnees||''}</li><li><b>Message :</b> ${c.message||''}</li></ul>`;
} else if (p.type === 'devis-infogerance') {
  sujet = `Devis infogérance ${String(p.tier||'').toUpperCase()} — ${c.societe||c.nom||''}`;
  const opts = (p.options||[]).map(o=>`<li>${o.label} × ${o.qty} = ${eur(o.total)}</li>`).join('');
  html = `<h2>Demande de devis — Infogérance ${String(p.tier||'').toUpperCase()}</h2>`+
    `<p><b>Société :</b> ${c.societe||''} — <b>${c.nom||''}</b> · ${c.email||''} · ${c.telephone||''}</p>`+
    `<h3>Parc</h3><ul>${Object.entries(p.parc||{}).map(([k,v])=>`<li>${k}: ${v}</li>`).join('')}</ul>`+
    (opts?`<h3>Options</h3><ul>${opts}</ul>`:'')+
    `<h3>Total</h3><p>Base HT : ${eur(p.base_ht)}<br>Remise : ${eur(p.remise_ht)}<br>`+
    `<b>Total HT/mois : ${eur(p.total_ht_mois)}</b><br>TVA 8,5% : ${eur(p.tva_ht)}<br>TTC/mois : ${eur(p.total_ttc_mois)}<br>`+
    `Engagement 36 mois : ${p.engagement_36_mois?'oui':'non'}</p>`+
    (c.message?`<p><b>Message :</b> ${c.message}</p>`:'');
} else if (p.type === 'devis-erp') {
  sujet = `Devis ERP — ${c.societe||c.nom||''}`;
  html = `<h2>Demande de devis — ERP Dolibarr</h2>`+
    `<p><b>Société :</b> ${c.societe||''} (SIRET ${c.siret||'-'}) — <b>${c.nom||''}</b> · ${c.email||''} · ${c.telephone||''}</p>`+
    `<p>Offre : ${p.offre||''}<br>Mensuel HT : ${eur(p.mensuel_ht)} × ${p.duree_mois||0} mois<br>`+
    `<b>Total HT : ${eur(p.total_ht)}</b><br>TVA 8,5% : ${eur(p.tva_ht)}<br>TTC : ${eur(p.total_ttc)}</p>`+
    (c.message?`<p><b>Besoins :</b> ${c.message}</p>`:'');
} else {
  sujet = 'Soumission inconnue'; html = '<pre>'+JSON.stringify(p,null,2)+'</pre>';
}
return [{ json: { sujet, html, emailClient: c.email || '', type: p.type } }];
